-- V91: Exercices Lecon 3 - Architecture MVC Controllers

-- =============================================
-- EXERCICE 1 : MealController - Lister et Ajouter (EASY)
-- =============================================

INSERT INTO exercises (lesson_id, title, difficulty, description, starter_code, solution_code, test_code, hints, xp_reward, order_index)
SELECT l.id,
    'MealController - Lister et Ajouter',
    'EASY',
    'Implementez la classe MealController qui encapsule un MealRepository. Le Controller doit avoir une methode list() qui affiche "[Repas] X repas disponibles :" suivi de chaque repas, et une methode add(String name, double price) qui ajoute un repas via le repository et affiche "[Repas] Nouveau repas ajoute : ..." avec le dernier repas de la liste.',
    E'import java.util.ArrayList;\nimport java.util.List;\n\nclass Meal {\n    private int id;\n    private String name;\n    private double price;\n    public Meal(int id, String name, double price) { this.id=id; this.name=name; this.price=price; }\n    public int getId() { return id; }\n    public String getName() { return name; }\n    public double getPrice() { return price; }\n    public String toString() { return "#"+id+" - "+name+" : "+price+" EUR"; }\n}\n\nclass MealRepository {\n    private List<Meal> meals = new ArrayList<>();\n    private int nextId = 1;\n    public void add(String name, double price) { meals.add(new Meal(nextId++, name, price)); }\n    public List<Meal> all() { return new ArrayList<>(meals); }\n    public Meal findById(int id) {\n        for (Meal m : meals) { if (m.getId()==id) return m; }\n        return null;\n    }\n}\n\n// TODO: Implementez la classe MealController\n// Elle recoit un MealRepository dans son constructeur\n// list() : affiche "[Repas] X repas disponibles :" puis chaque repas\n// add(String name, double price) : ajoute via le repo,\n//   puis affiche "[Repas] Nouveau repas ajoute : " + le dernier element de all()\n\npublic class Main {\n    public static void main(String[] args) {\n        MealRepository repo = new MealRepository();\n        repo.add("Pizza Margherita", 12.5);\n        repo.add("Burger Classic", 9.9);\n        repo.add("Salade Caesar", 8.5);\n\n        MealController controller = new MealController(repo);\n        controller.list();\n\n        controller.add("Pates Carbonara", 11.0);\n        controller.list();\n    }\n}',
    E'import java.util.ArrayList;\nimport java.util.List;\n\nclass Meal {\n    private int id;\n    private String name;\n    private double price;\n    public Meal(int id, String name, double price) { this.id=id; this.name=name; this.price=price; }\n    public int getId() { return id; }\n    public String getName() { return name; }\n    public double getPrice() { return price; }\n    public String toString() { return "#"+id+" - "+name+" : "+price+" EUR"; }\n}\n\nclass MealRepository {\n    private List<Meal> meals = new ArrayList<>();\n    private int nextId = 1;\n    public void add(String name, double price) { meals.add(new Meal(nextId++, name, price)); }\n    public List<Meal> all() { return new ArrayList<>(meals); }\n    public Meal findById(int id) {\n        for (Meal m : meals) { if (m.getId()==id) return m; }\n        return null;\n    }\n}\n\nclass MealController {\n    private MealRepository repository;\n\n    public MealController(MealRepository repository) {\n        this.repository = repository;\n    }\n\n    public void list() {\n        List<Meal> meals = repository.all();\n        System.out.println("[Repas] " + meals.size() + " repas disponibles :");\n        for (Meal m : meals) {\n            System.out.println(m);\n        }\n    }\n\n    public void add(String name, double price) {\n        repository.add(name, price);\n        List<Meal> all = repository.all();\n        Meal added = all.get(all.size() - 1);\n        System.out.println("[Repas] Nouveau repas ajoute : " + added);\n    }\n}\n\npublic class Main {\n    public static void main(String[] args) {\n        MealRepository repo = new MealRepository();\n        repo.add("Pizza Margherita", 12.5);\n        repo.add("Burger Classic", 9.9);\n        repo.add("Salade Caesar", 8.5);\n\n        MealController controller = new MealController(repo);\n        controller.list();\n\n        controller.add("Pates Carbonara", 11.0);\n        controller.list();\n    }\n}',
    'output.contains("[Repas] 3 repas disponibles :") && output.contains("#1 - Pizza Margherita : 12.5 EUR") && output.contains("[Repas] Nouveau repas ajoute : #4 - Pates Carbonara : 11.0 EUR") && output.contains("[Repas] 4 repas disponibles :")',
    '["MealController recoit MealRepository dans son constructeur : public MealController(MealRepository repository) { this.repository = repository; }", "list() appelle repository.all() pour obtenir la liste, puis affiche \"[Repas] \" + meals.size() + \" repas disponibles :\" et parcourt la liste", "add() appelle d abord repository.add(name, price), puis recupere le dernier element avec all().get(all.size()-1) pour l afficher"]',
    30,
    1
FROM lessons l WHERE l.slug = 'mvc-controllers';

-- =============================================
-- EXERCICE 2 : Application Complete - 2 Controllers (MEDIUM)
-- =============================================

INSERT INTO exercises (lesson_id, title, difficulty, description, starter_code, solution_code, test_code, hints, xp_reward, order_index)
SELECT l.id,
    'Application Complete - 2 Controllers',
    'MEDIUM',
    'Implementez CustomerController sur le modele de MealController. Puis, dans Main, instanciez les deux repositories et les deux controllers. Ajoutez 3 repas et 2 clients, puis utilisez les controllers pour afficher "=== Systeme de Livraison ===" suivi de la liste des repas et la liste des clients.',
    E'import java.util.ArrayList;\nimport java.util.List;\n\nclass Meal {\n    private int id; private String name; private double price;\n    public Meal(int id, String name, double price) { this.id=id; this.name=name; this.price=price; }\n    public int getId() { return id; }\n    public String getName() { return name; }\n    public double getPrice() { return price; }\n    public String toString() { return "#"+id+" - "+name+" : "+price+" EUR"; }\n}\n\nclass Customer {\n    private int id; private String name; private String address;\n    public Customer(int id, String name, String address) { this.id=id; this.name=name; this.address=address; }\n    public int getId() { return id; }\n    public String getName() { return name; }\n    public String getAddress() { return address; }\n    public String toString() { return "#"+id+" - "+name+" | "+address; }\n}\n\nclass MealRepository {\n    private List<Meal> meals = new ArrayList<>();\n    private int nextId = 1;\n    public void add(String name, double price) { meals.add(new Meal(nextId++, name, price)); }\n    public List<Meal> all() { return new ArrayList<>(meals); }\n}\n\nclass CustomerRepository {\n    private List<Customer> customers = new ArrayList<>();\n    private int nextId = 1;\n    public void add(String name, String address) { customers.add(new Customer(nextId++, name, address)); }\n    public List<Customer> all() { return new ArrayList<>(customers); }\n}\n\nclass MealController {\n    private MealRepository repository;\n    public MealController(MealRepository repository) { this.repository = repository; }\n    public void list() {\n        List<Meal> meals = repository.all();\n        System.out.println("[Repas] " + meals.size() + " repas disponibles :");\n        for (Meal m : meals) System.out.println(m);\n    }\n}\n\n// TODO: Implementez CustomerController\n// Elle recoit un CustomerRepository dans son constructeur\n// list() : affiche "[Clients] X clients enregistres :" puis chaque client\n\npublic class Main {\n    public static void main(String[] args) {\n        MealRepository mealRepo = new MealRepository();\n        CustomerRepository customerRepo = new CustomerRepository();\n\n        mealRepo.add("Pizza Margherita", 12.5);\n        mealRepo.add("Burger Classic", 9.9);\n        mealRepo.add("Salade Caesar", 8.5);\n        customerRepo.add("Jean Dupont", "12 rue de la Paix, Paris");\n        customerRepo.add("Marie Martin", "5 avenue Victor Hugo, Lyon");\n\n        MealController mealCtrl = new MealController(mealRepo);\n        CustomerController customerCtrl = new CustomerController(customerRepo);\n\n        System.out.println("=== Systeme de Livraison ===");\n        mealCtrl.list();\n        customerCtrl.list();\n    }\n}',
    E'import java.util.ArrayList;\nimport java.util.List;\n\nclass Meal {\n    private int id; private String name; private double price;\n    public Meal(int id, String name, double price) { this.id=id; this.name=name; this.price=price; }\n    public int getId() { return id; }\n    public String getName() { return name; }\n    public double getPrice() { return price; }\n    public String toString() { return "#"+id+" - "+name+" : "+price+" EUR"; }\n}\n\nclass Customer {\n    private int id; private String name; private String address;\n    public Customer(int id, String name, String address) { this.id=id; this.name=name; this.address=address; }\n    public int getId() { return id; }\n    public String getName() { return name; }\n    public String getAddress() { return address; }\n    public String toString() { return "#"+id+" - "+name+" | "+address; }\n}\n\nclass MealRepository {\n    private List<Meal> meals = new ArrayList<>();\n    private int nextId = 1;\n    public void add(String name, double price) { meals.add(new Meal(nextId++, name, price)); }\n    public List<Meal> all() { return new ArrayList<>(meals); }\n}\n\nclass CustomerRepository {\n    private List<Customer> customers = new ArrayList<>();\n    private int nextId = 1;\n    public void add(String name, String address) { customers.add(new Customer(nextId++, name, address)); }\n    public List<Customer> all() { return new ArrayList<>(customers); }\n}\n\nclass MealController {\n    private MealRepository repository;\n    public MealController(MealRepository repository) { this.repository = repository; }\n    public void list() {\n        List<Meal> meals = repository.all();\n        System.out.println("[Repas] " + meals.size() + " repas disponibles :");\n        for (Meal m : meals) System.out.println(m);\n    }\n}\n\nclass CustomerController {\n    private CustomerRepository repository;\n\n    public CustomerController(CustomerRepository repository) {\n        this.repository = repository;\n    }\n\n    public void list() {\n        List<Customer> customers = repository.all();\n        System.out.println("[Clients] " + customers.size() + " clients enregistres :");\n        for (Customer c : customers) {\n            System.out.println(c);\n        }\n    }\n}\n\npublic class Main {\n    public static void main(String[] args) {\n        MealRepository mealRepo = new MealRepository();\n        CustomerRepository customerRepo = new CustomerRepository();\n\n        mealRepo.add("Pizza Margherita", 12.5);\n        mealRepo.add("Burger Classic", 9.9);\n        mealRepo.add("Salade Caesar", 8.5);\n        customerRepo.add("Jean Dupont", "12 rue de la Paix, Paris");\n        customerRepo.add("Marie Martin", "5 avenue Victor Hugo, Lyon");\n\n        MealController mealCtrl = new MealController(mealRepo);\n        CustomerController customerCtrl = new CustomerController(customerRepo);\n\n        System.out.println("=== Systeme de Livraison ===");\n        mealCtrl.list();\n        customerCtrl.list();\n    }\n}',
    'output.contains("=== Systeme de Livraison ===") && output.contains("[Repas] 3 repas disponibles :") && output.contains("[Clients] 2 clients enregistres :") && output.contains("Jean Dupont") && output.contains("Pizza Margherita")',
    '["CustomerController est identique a MealController mais travaille avec CustomerRepository et Customer", "Le message de list() doit etre : \"[Clients] \" + customers.size() + \" clients enregistres :\"", "Dans Main, creez les repositories, ajoutez les donnees, puis creez les controllers en leur passant les repositories : new MealController(mealRepo)"]',
    40,
    2
FROM lessons l WHERE l.slug = 'mvc-controllers';

-- =============================================
-- EXERCICE 3 : BaseRepository avec Generiques (HARD)
-- =============================================

INSERT INTO exercises (lesson_id, title, difficulty, description, starter_code, solution_code, test_code, hints, xp_reward, order_index)
SELECT l.id,
    'BaseRepository avec Generiques',
    'HARD',
    'Implementez une classe abstraite BaseRepository<T> avec les champs protected List<T> items et protected int nextId. Elle doit fournir all() (copie defensive), delete(int id) avec removeIf, et la methode abstraite protected abstract int getId(T item). MealRepository et CustomerRepository doivent etendre BaseRepository et implementer getId().',
    E'import java.util.ArrayList;\nimport java.util.List;\n\nclass Meal {\n    private int id; private String name; private double price;\n    public Meal(int id, String name, double price) { this.id=id; this.name=name; this.price=price; }\n    public int getId() { return id; }\n    public String getName() { return name; }\n    public double getPrice() { return price; }\n    public String toString() { return "#"+id+" - "+name+" : "+price+" EUR"; }\n}\n\nclass Customer {\n    private int id; private String name; private String address;\n    public Customer(int id, String name, String address) { this.id=id; this.name=name; this.address=address; }\n    public int getId() { return id; }\n    public String getName() { return name; }\n    public String toString() { return "#"+id+" - "+name; }\n}\n\n// TODO: Implementez abstract class BaseRepository<T>\n// protected List<T> items = new ArrayList<>()\n// protected int nextId = 1\n// public List<T> all() -> retourne new ArrayList<>(items)\n// public boolean delete(int id) -> items.removeIf(item -> getId(item) == id)\n// protected abstract int getId(T item)\n\n// TODO: class MealRepository extends BaseRepository<Meal>\n// public void add(String name, double price)\n// @Override protected int getId(Meal meal) -> return meal.getId()\n\n// TODO: class CustomerRepository extends BaseRepository<Customer>\n// public void add(String name, String address)\n// @Override protected int getId(Customer customer) -> return customer.getId()\n\npublic class Main {\n    public static void main(String[] args) {\n        MealRepository mealRepo = new MealRepository();\n        mealRepo.add("Pizza Margherita", 12.5);\n        mealRepo.add("Burger Classic", 9.9);\n        mealRepo.add("Salade Caesar", 8.5);\n\n        CustomerRepository customerRepo = new CustomerRepository();\n        customerRepo.add("Jean Dupont", "12 rue de la Paix, Paris");\n        customerRepo.add("Marie Martin", "5 avenue Victor Hugo, Lyon");\n\n        System.out.println("MealRepository contient " + mealRepo.all().size() + " elements");\n        System.out.println("CustomerRepository contient " + customerRepo.all().size() + " elements");\n\n        mealRepo.delete(2);\n        System.out.println("Apres delete : " + mealRepo.all().size() + " repas");\n        System.out.println("Heritage verifie !");\n    }\n}',
    E'import java.util.ArrayList;\nimport java.util.List;\n\nclass Meal {\n    private int id; private String name; private double price;\n    public Meal(int id, String name, double price) { this.id=id; this.name=name; this.price=price; }\n    public int getId() { return id; }\n    public String getName() { return name; }\n    public double getPrice() { return price; }\n    public String toString() { return "#"+id+" - "+name+" : "+price+" EUR"; }\n}\n\nclass Customer {\n    private int id; private String name; private String address;\n    public Customer(int id, String name, String address) { this.id=id; this.name=name; this.address=address; }\n    public int getId() { return id; }\n    public String getName() { return name; }\n    public String toString() { return "#"+id+" - "+name; }\n}\n\nabstract class BaseRepository<T> {\n    protected List<T> items = new ArrayList<>();\n    protected int nextId = 1;\n\n    public List<T> all() {\n        return new ArrayList<>(items);\n    }\n\n    public boolean delete(int id) {\n        return items.removeIf(item -> getId(item) == id);\n    }\n\n    protected abstract int getId(T item);\n}\n\nclass MealRepository extends BaseRepository<Meal> {\n    public void add(String name, double price) {\n        items.add(new Meal(nextId++, name, price));\n    }\n\n    @Override\n    protected int getId(Meal meal) {\n        return meal.getId();\n    }\n}\n\nclass CustomerRepository extends BaseRepository<Customer> {\n    public void add(String name, String address) {\n        items.add(new Customer(nextId++, name, address));\n    }\n\n    @Override\n    protected int getId(Customer customer) {\n        return customer.getId();\n    }\n}\n\npublic class Main {\n    public static void main(String[] args) {\n        MealRepository mealRepo = new MealRepository();\n        mealRepo.add("Pizza Margherita", 12.5);\n        mealRepo.add("Burger Classic", 9.9);\n        mealRepo.add("Salade Caesar", 8.5);\n\n        CustomerRepository customerRepo = new CustomerRepository();\n        customerRepo.add("Jean Dupont", "12 rue de la Paix, Paris");\n        customerRepo.add("Marie Martin", "5 avenue Victor Hugo, Lyon");\n\n        System.out.println("MealRepository contient " + mealRepo.all().size() + " elements");\n        System.out.println("CustomerRepository contient " + customerRepo.all().size() + " elements");\n\n        mealRepo.delete(2);\n        System.out.println("Apres delete : " + mealRepo.all().size() + " repas");\n        System.out.println("Heritage verifie !");\n    }\n}',
    'output.contains("MealRepository contient 3 elements") && output.contains("CustomerRepository contient 2 elements") && output.contains("Apres delete : 2 repas") && output.contains("Heritage verifie !")',
    '["abstract class BaseRepository<T> : le <T> est le parametre generique qui sera remplace par Meal ou Customer selon la sous-classe", "La methode delete utilise une lambda : items.removeIf(item -> getId(item) == id). La methode abstraite getId(T item) est definie dans chaque sous-classe", "MealRepository extends BaseRepository<Meal> et CustomerRepository extends BaseRepository<Customer>. Chaque sous-classe implemente getId() en appelant .getId() sur son type specifique"]',
    50,
    3
FROM lessons l WHERE l.slug = 'mvc-controllers';
